CREATE TABLE `apichain_project_request` (
  `id` int NOT NULL AUTO_INCREMENT,
  `team_id` char(64) NOT NULL,
  `url` char(255) NOT NULL,
  `method` char(20) NOT NULL,
  `title` char(255) NOT NULL,
  `description` text,
  `fold` char(64) DEFAULT NULL,
  `project` char(64) DEFAULT NULL,
  `pic_flg` tinyint(1) DEFAULT NULL,
  `file_flg` tinyint(1) DEFAULT NULL,
  `json_flg` tinyint(1) DEFAULT NULL,
  `html_flg` tinyint(1) DEFAULT NULL,
  `header` json DEFAULT NULL,
  `param` json DEFAULT NULL,
  `path_variable` json DEFAULT NULL,
  `body` json DEFAULT NULL,
  `sort` int DEFAULT NULL,
  `response` json DEFAULT NULL,
  `response_demo` text,
  `rhead` json DEFAULT NULL,
  `cookie` json DEFAULT NULL,
  `create_uid` char(200) NOT NULL,
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `del_flg` tinyint(1) NOT NULL,
  `vector_store_flg` tinyint DEFAULT '0' COMMENT '是否存储到了向量数据库',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
